import './Page.css'
import Header from './Header.js'

function Page({ children }) {
  return (
    <div className='text-slate-200 bg-slate-950 w-screen h-screen justify-center'>
      <Header />
      <div className='grid place-content-top space-y-5'>
        { children }
      </div>
    </div>
  );
}

export default Page;
